const data = $input.all().map(i => i.json);

const districts = [...new Set(data.map(d => d.districtname))];

const last7 = districts.map(d => {
  const row = data.find(r => r.districtname === d && r.period_label === "last_7_days");
  return row ? parseFloat(row.total_sales) : 0;
});

const prev7 = districts.map(d => {
  const row = data.find(r => r.districtname === d && r.period_label === "previous_7_days");
  return row ? parseFloat(row.total_sales) : 0;
});

const chartConfig = {
  type: "bar",
  data: {
    labels: districts,
    datasets: [
      { label: "Last 7 Days Sales", data: last7, backgroundColor: "rgba(54,162,235,0.6)" },
      { label: "Previous 7 Days Sales", data: prev7, backgroundColor: "rgba(255,99,132,0.6)" }
    ]
  },
  options: {
    title: { display: true, text: "Weekly Sales by District" },
    responsive: true
  }
};

// Create the QuickChart URL (encode the chart config)
const url = "https://quickchart.io/chart?c=" + encodeURIComponent(JSON.stringify(chartConfig));

return [{
  json: {
    url
  }
}];

const data = $input.all().map(i => i.json);

// Get all unique districts
const districts = [...new Set(data.map(d => d.district))];

// Build table header
let table = "District | Last 7 Days Sales | Last 7 Days Margin | Previous 7 Days Sales | Previous 7 Days Margin\n";
table += "-------- | ---------------- | ---------------- | ------------------- | -------------------\n";

// Populate table rows
districts.forEach(d => {
  const lastWeek = data.find(i => i.district === d && i.period === "last_7_days");
  const prevWeek = data.find(i => i.district === d && i.period === "previous_7_days");

  table += `${d} | ${lastWeek ? lastWeek.sales : 0} | ${lastWeek ? lastWeek.margin : 0} | ${prevWeek ? prevWeek.sales : 0} | ${prevWeek ? prevWeek.margin : 0}\n`;
});

return [{
  json: {
    llm_table: table
  }
}];

const data = $input.all().map(i => i.json);

// convert total_sales and total_margin to float
const formatted = data.map(r => ({
  district: r.districtname,
  period: r.period_label,
  sales: parseFloat(r.total_sales),
  margin: parseFloat(r.total_margin)
}));

return formatted.map(row => ({ json: row }));

